// Server-side gate + SLA computation for incoming service requests.
// ACCESS_CODE must match SUPPORT_ACCESS_CODE in the website's src/config.js.
const ACCESS_CODE = 'ICVAHCS-2026';

const b = $input.first().json.body || $input.first().json;

if (!b.accessCode || String(b.accessCode).trim().toUpperCase() !== ACCESS_CODE.toUpperCase()) {
  // Silently drop submissions that bypass the website's client-side check.
  return [];
}
if (!b.ticketId || !b.email || !b.description) {
  return [];
}

const submitted = b.timestamp ? new Date(b.timestamp) : new Date();
const isEmergency = b.urgency === 'Major / Emergency';
const slaHours = isEmergency ? 4 : 24;
const slaDue = new Date(submitted.getTime() + slaHours * 3600 * 1000);
const reportMonth = `${submitted.getFullYear()}-${String(submitted.getMonth() + 1).padStart(2, '0')}`;

return [{ json: {
  ticketId: String(b.ticketId).toUpperCase(),
  name: b.name || '',
  role: b.role || '',
  email: b.email,
  phone: b.phone || '',
  equipment: b.equipment || 'Other / Not Sure',
  location: b.location || '',
  urgency: b.urgency || 'Minor / Routine',
  description: b.description,
  callback: b.callback || '',
  submittedAt: submitted.toISOString(),
  slaDue: slaDue.toISOString(),
  reportMonth,
  isEmergency,
}}];

